if (! function_exists('data_rank')) {
    function data_rank($values, $method = null, $ascending = null)
    {
        if (!is_array($values) || count($values) < 1) {
            return json_encode(['error' => 'Non-empty array of values required']);
        }
        $method = isset($method) ? $method : 'competition';
        $ascending = isset($ascending) ? (bool)$ascending : true;
        $n = count($values);

        // Create index-value pairs
        $pairs = [];
        foreach ($values as $i => $v) {
            $pairs[] = ['index' => $i, 'value' => $v];
        }

        // Sort by value
        usort($pairs, function($a, $b) use ($ascending) {
            if ($a['value'] == $b['value']) return 0;
            return $ascending ? ($a['value'] < $b['value'] ? -1 : 1) : ($a['value'] > $b['value'] ? -1 : 1);
        });

        // Assign ranks
        $ranks = array_fill(0, $n, 0);
        $i = 0;
        while ($i < $n) {
            // Find all ties starting at position i
            $j = $i;
            while ($j < $n && $pairs[$j]['value'] == $pairs[$i]['value']) {
                $j++;
            }
            $tieCount = $j - $i;
            
            if ($tieCount === 1) {
                // No tie
                $rank = $method === 'dense' ? ($i + 1) : ($i + 1);
                $ranks[$pairs[$i]['index']] = (float)$rank;
            } else {
                // Handle tie
                switch ($method) {
                    case 'competition':
                        $rank = $i + 1;
                        for ($k = $i; $k < $j; $k++) {
                            $ranks[$pairs[$k]['index']] = (float)$rank;
                        }
                        break;
                    case 'dense':
                        $rank = ($i > 0 && $pairs[$i-1]['value'] == $pairs[$i]['value']) 
                            ? $ranks[$pairs[$i-1]['index']] 
                            : ($i + 1 - ($tieCount > 1 ? 0 : 0));
                        // Find the actual dense rank
                        $denseRank = 1;
                        for ($prev = 0; $prev < $i; $prev++) {
                            if ($prev === 0 || $pairs[$prev]['value'] != $pairs[$prev-1]['value']) {
                                $denseRank++;
                            }
                        }
                        for ($k = $i; $k < $j; $k++) {
                            $ranks[$pairs[$k]['index']] = (float)$denseRank;
                        }
                        break;
                    case 'ordinal':
                        for ($k = $i; $k < $j; $k++) {
                            $ranks[$pairs[$k]['index']] = (float)($k + 1);
                        }
                        break;
                    case 'average':
                        $avg = ($i + 1 + $j) / 2.0;
                        for ($k = $i; $k < $j; $k++) {
                            $ranks[$pairs[$k]['index']] = $avg;
                        }
                        break;
                    case 'min':
                        for ($k = $i; $k < $j; $k++) {
                            $ranks[$pairs[$k]['index']] = (float)($i + 1);
                        }
                        break;
                    case 'max':
                        for ($k = $i; $k < $j; $k++) {
                            $ranks[$pairs[$k]['index']] = (float)($j);
                        }
                        break;
                    default:
                        $rank = $i + 1;
                        for ($k = $i; $k < $j; $k++) {
                            $ranks[$pairs[$k]['index']] = (float)$rank;
                        }
                }
            }
            $i = $j;
        }

        // Build output
        $rankedPairs = [];
        for ($i = 0; $i < $n; $i++) {
            $rankedPairs[] = [
                'index' => $i,
                'value' => $values[$i],
                'rank' => $ranks[$i],
            ];
        }

        // Count ties
        $tieGroups = 0;
        $i = 0;
        $sortedValues = array_map(function($p) { return $p['value']; }, $pairs);
        while ($i < $n) {
            $j = $i;
            while ($j < $n && $sortedValues[$j] == $sortedValues[$i]) $j++;
            if ($j - $i > 1) $tieGroups++;
            $i = $j;
        }

        return json_encode([
            'n' => $n,
            'method' => $method,
            'ascending' => $ascending,
            'tie_groups' => $tieGroups,
            'has_ties' => $tieGroups > 0,
            'ranks' => $ranks,
            'ranked_data' => $rankedPairs,
            'next_steps' => [
                "Pass original values as x and ranks as y to data_correlator for Spearman correlation.",
                "Use with data_normalizer then math_statistics for non-parametric analysis.",
            ],
        ]);
    }
